function n(){chrome.contextMenus.removeAll(()=>{chrome.contextMenus.create({id:"easytranslate-selection",title:"用 EasyTranslate 翻译「%s」",contexts:["selection"]})})}chrome.runtime.onInstalled.addListener(n);chrome.runtime.onStartup.addListener(n);chrome.contextMenus.onClicked.addListener((t,e)=>{t.menuItemId==="easytranslate-selection"&&(e!=null&&e.id)&&chrome.tabs.sendMessage(e.id,{type:"translate-selection",text:t.selectionText})});
